        SELECT SEQ_STATION.NEXTVAL FROM DUAL


	INSERT
	  INTO
		   STATION
		   (
		   STATION_NO
		 , STATION_NAME
		 , REGION
		 , ADDRESS
		 , STATION_DESC
		 , LAT
		 , LNG
		   )
	VALUES
		   (
			#{stationNo}
		  , #{stationName}
		  , #{region}
		  , #{address}
		  , #{stationDesc}
		  , #{lat}
		  , #{lng}
		   )

mapper.update:
UPDATE
	   STATION
   SET
	   STATION_NAME = #{stationName}
	 , STATION_DESC = #{stationDesc}
	 , REGION = #{region}
	 , ADDRESS = #{address}
	 , LAT = #{lat}
	 , LNG = #{lng}
	 , STATUS = #{status}
 WHERE
	   STATION_NO = #{stationNo}

mapper.select:
SELECT
	   COUNT(*)
  FROM
	   STATION
 WHERE
	   LAT = #{lat}
   AND
	   LNG = #{lng}
   AND
	   STATION_NO != #{stationNo}
